TASKS = [
    {
        "name": "tabletop_pick_and_place",
        "task_type": "tabletop pick-and-place",
        "available_data": {"real_demos": 50, "sim_demos": 200, "video_demos": 0},
    },
    {
        "name": "liquid_pouring",
        "task_type": "liquid pouring",
        "available_data": {"real_demos": 20, "sim_demos": 0, "video_demos": 10},
    },
    {
        "name": "articulated_door_open",
        "task_type": "articulated door manipulation",
        "available_data": {"real_demos": 8, "sim_demos": 0, "video_demos": 5},
    },
]

# ── Step 1: suggest_data_mix per task ─────────────────────────────────────────
raw_results = {}
for task in TASKS:
    result = suggest_data_mix(
        task_type=task["task_type"],
        available_data=task["available_data"],
    )
    print(f"[MIX] {task['name']}: {result}")
    raw_results[task["name"]] = result if isinstance(result, dict) else {}

# ── Step 2: Extract raw weights (inlined — no helper function) ────────────────
# suggest_data_mix may return 'recommended_weight', 'weight', or 'sampling_weight'.
# Fall back to total demo count as proportional heuristic if key absent.
WEIGHT_KEYS = ("recommended_weight", "weight", "sampling_weight", "task_weight")
raw_weights = {}
for task in TASKS:
    tname = task["name"]
    r = raw_results[tname]
    w = next(
        (float(r[k]) for k in WEIGHT_KEYS if k in r and isinstance(r[k], (int, float)) and r[k] > 0),
        float(max(sum(task["available_data"].values()), 1)),
    )
    raw_weights[tname] = w

# ── Step 3: Normalise weights ─────────────────────────────────────────────────
weight_sum = sum(raw_weights.values())
norm_weights = {k: round(v / weight_sum, 4) for k, v in raw_weights.items()}

sampling_schedule = {}
for task in TASKS:
    sampling_schedule[task["name"]] = {
        "task_type": task["task_type"],
        "available_data": task["available_data"],
        "raw_suggestion": raw_results[task["name"]],
        "weight": norm_weights[task["name"]],
    }

# ── Step 4: Audit corpus (informational) ──────────────────────────────────────
stats = finetune_stats()
print(f"[STATS] {stats}")

# ── Step 5: Persist result ────────────────────────────────────────────────────
payload = {
    "sampling_schedule": sampling_schedule,
    "finetune_stats": stats if isinstance(stats, dict) else None,
}
pass  # removed sandbox-illegal `with open(...)` block

# ── Step 6: Success gate ──────────────────────────────────────────────────────
schedule = payload["sampling_schedule"]
missing_tasks = [t["name"] for t in TASKS if t["name"] not in schedule]
zero_weight_tasks = [k for k, v in schedule.items() if v.get("weight", 0) <= 0]

if missing_tasks:
    print(f"[WARN] Missing tasks in schedule: {missing_tasks}")
elif zero_weight_tasks:
    print(f"[WARN] Zero-weight tasks: {zero_weight_tasks}")
else:
    print(
        f"[OK] Multi-task data mix schedule ready ({len(schedule)} tasks): "
        + ", ".join(f"{k}={v['weight']:.4f}" for k, v in schedule.items())
        + f" -> {RESULT_FILE}"
    )

assert len(schedule) == 3, f"Expected 3 task keys in sampling_schedule, got {len(schedule)}"
assert all(v.get('weight', 0) > 0 for v in schedule.values()), "All task weights must be > 0"

